INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Développement d''une application avancée avec API', 'Formation sur le développement d’applications modernes.', 15, 300000.00, 'entreprise', '2026-05-15', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Comprendre les architectures modernes (monolithique, microservices, MVC, API First)\n• Savoir concevoir et documenter une API RESTful\n• Maîtriser la persistance des données avec PostgreSQL et ORM\n• Développer un frontend moderne connecté au backend\n• Intégrer la sécurité (JWT, OAuth2, CORS, rate limiting)\n• Améliorer la qualité avec tests unitaires et CI/CD\n• Optimiser les performances et préparer la montée en charge\n• Déployer une application sur VPS ou Cloud avec Docker et Nginx\n• Réaliser un projet complet encadré pour valider les compétences\n\n--- OBJECTIFS DÉTAILLÉS ---\nFormer des développeurs capables de concevoir, coder, sécuriser et déployer une application complète. Développer des compétences transversales en backend, frontend, base de données, sécurité et DevOps. Préparer les participants à travailler sur des projets professionnels ou à lancer leurs propres solutions logicielles.\n\n--- PRÉREQUIS ---\nConnaissances de base en programmation (PHP, JavaScript ou Python), notions de bases de données relationnelles. Une expérience préalable en développement est un plus mais non obligatoire.\n\n--- CONTENU ---\nMODULE 1 – Architecture et conception d’applications modernes\nMODULE 2 – Protocole HTTP & API REST\nMODULE 3 – Développement du Backend (API)\nMODULE 4 – Base de données & persistance\nMODULE 5 – Sécurité des applications & API\nMODULE 6 – Développement Frontend & consommation d’API\nMODULE 7 – Tests et qualité logicielle\nMODULE 8 – Performances et optimisation\nMODULE 9 – Déploiement et DevOps (Introduction)\nMODULE 10 – Projet final (Full API App)\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nDéveloppeurs débutants à intermédiaires, étudiants en informatique, professionnels souhaitant monter en compétence sur le développement moderne, responsables techniques désirant comprendre les architectures actuelles.\n\n--- MÉTHODES ---\nCours théoriques illustrés, démonstrations pratiques, ateliers de codage en groupe, études de cas réels, projet final encadré avec soutenance.\n\n--- SUPPORTS ---\nPostgreSQL, Laravel, React.js, Docker, Swagger/OpenAPI, Git & GitHub, Postman/Insomnia pour tests API, Redis pour cache, Nginx pour déploiement, outils CI/CD (GitHub Actions, GitLab CI).\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
